mapper.update:
UPDATE batches SET batch_code=#{batchCode}, entry_date=#{entryDate}, breed=#{breed},
    source=#{source}, initial_pen_id=#{initialPenId}, notes=#{notes}
WHERE id = #{id}

mapper.select:
SELECT b.*, p.pen_name as initial_pen_name, (SELECT COUNT(*) FROM animals WHERE batch_id = b.id) as animal_count FROM batches b LEFT JOIN pens p ON b.initial_pen_id = p.id
(b.batch_code LIKE CONCAT('%', #{search}, '%') OR b.breed LIKE CONCAT('%', #{search}, '%') OR b.source LIKE CONCAT('%', #{search}, '%'))
ORDER BY b.entry_date DESC LIMIT #{size} OFFSET #{offset}
